var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`그 시절의 기억은 변함없이 고통스럽다.`,JPN:`あの頃の記憶は相変わらず苦痛だ。`,ENG:`Remembering those days never gets any easier.`,TWN:`那個時候的記憶總是痛苦的。`},stage:{bg:`WHITE`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`아무리 잊으려고 애를 써도, 눈을 감으면 떠오르는 것은 항상 그 하얀 설원이었다.`,JPN:`いくら忘れようとしても、目を閉じると浮かぶのはいつもあの白い雪原だった。`,ENG:`No matter how hard I try to forget it all, I keep seeing that white, snowy field whenever I close my eyes.`,TWN:`就算努力想忘掉，但只要一閉上眼睛，眼前總是浮現那片雪白的雪地。`},stage:{bg:`WHITE`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`따듯한 피가 흘러내릴수록, 몸은 차갑게 식어만 간다.`,JPN:`温かい血が流れ落ち、体は冷めていく。`,ENG:`With every trickle of steaming blood, my body grows ever colder.`,TWN:`溫熱的血液不斷流出，身體也越來越冷。`},stage:{bg:`MAINSTREAM_7030010`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`모든 것을 지워 버리려는 듯, 눈보라가 몰아친다.`,JPN:`すべてを消し去ろうとするような吹雪に襲われる。`,ENG:`A blizzard blows over, as if trying to wipe everything from existence.`,TWN:`暴風雪彷彿是要吹散一切似地呼嘯著。`},stage:{bg:`MAINSTREAM_7030010`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`그리고 의식이 끊어지기 직전.`,JPN:`そして、意識が途絶える直前。`,ENG:`And right before I black out…`,TWN:`而在失去意識之前，`},stage:{bg:`WHITE`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`눈보라를 헤치고 나타난 것은,`,JPN:`吹雪の中から現れたのは、`,ENG:`…a figure appeared through the blizzard.`,TWN:`越過暴風雪出現的，`},stage:{bg:`WHITE`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`회색 머리칼의, 다른 세상에서 온 것 같은 소녀였다.`,JPN:`銀髪の、まるで異世界から来たかのような雰囲気の少女だった。`,ENG:`It was a silver-haired girl, who seemed to be from another world.`,TWN:`是一位有著灰色頭髮，彷彿是從另一個世界而來的少女。`},stage:{bg:`WHITE`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`……피를 많이 흘렸군.`,JPN:`……かなり出血しているな。`,ENG:`…You've bled too much.`,TWN:`……你流了好多血。`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`이름이 뭐지? 말은 할 수 있나?`,JPN:`名前は？　喋れるか？`,ENG:`What's your name? Can you talk?`,TWN:`你叫什麼名字？可以說話嗎？`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`주……. 시윤…….`,JPN:`アキヤマ……シリュウ……`,ENG:`Joo… Shiyoon…`,TWN:`周……時雲……`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`그래, 주시윤.`,JPN:`そうか、アキヤマ・シリュウ。`,ENG:`Very well, Joo Shiyoon.`,TWN:`喔喔，周時雲。`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`그런 상태로 여기 있으면 금방 얼어 죽을 거다.`,JPN:`そんな状態でここにいたら、すぐ凍死してもおかしくない。`,ENG:`You'll freeze to death if you stay here.`,TWN:`你繼續待在這裡會凍死的。`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`내게 안기도록. 적당한 곳까지 옮겨 주마.`,JPN:`抱きかかえて、適当な所まで運んでやろう。`,ENG:`Take my hand. I'll move you to a more suitable place.`,TWN:`我抱你去安全的地方吧。`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`당신은…… 누구죠?`,JPN:`あなたは……誰ですか？`,ENG:`Who… are you?`,TWN:`你……是誰？`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`……힐데라고 불러라.`,JPN:`……ヒルデと呼べ。`,ENG:`…You can call me Hilde.`,TWN:`……你叫我希爾德吧。`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`나에 대해선 그것만 알면 된다.`,JPN:`私についてはそれだけでいい。`,ENG:`That's all you need to know about me.`,TWN:`其他你不需要知道。`},stage:{bg:`MAINSTREAM_7030011`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:null,text:{KOREA:`그녀는 나를 창고로 옮겨 상처를 치료해 줬다.`,JPN:`彼女は僕を倉庫に連れて行き、傷を治療してくれた。`,ENG:`She moved me to a warehouse and treated my wounds.`,TWN:`她把我帶到倉庫，為我療傷。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`그리고는 잠시 나를 내려 보다가, 어딘가로 사라졌다.`,JPN:`そしてしばらく僕を見下ろして、どこかに消えた。`,ENG:`Then she briefly looked down at me, only to disappear.`,TWN:`然後看了我一眼就消失了。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}}];export{e as default};